<section class="grid lg:grid-cols-3 gap-5"><div class="lg:col-span-2 border rounded-2xl p-5"><div class="flex justify-between"><h2 class="font-semibold">Operación</h2><button onclick="openHours()" class="text-emerald-700 text-sm font-semibold">+ Horario</button></div><div class="grid sm:grid-cols-3 gap-3 mt-4"><button onclick="entity('servicios')" class="border hover:border-emerald-500 rounded-xl p-4 text-left"><b>Servicios</b><span class="block text-xs text-slate-500 mt-1">Duración y aprobación</span></button><button onclick="entity('profesionales')" class="border hover:border-emerald-500 rounded-xl p-4 text-left"><b>Profesionales</b><span class="block text-xs text-slate-500 mt-1">Preferencias y horarios</span></button><button onclick="entity('sucursales')" class="border hover:border-emerald-500 rounded-xl p-4 text-left"><b>Sucursales</b><span class="block text-xs text-slate-500 mt-1">Ubicación de atención</span></button></div><div class="mt-5 border-t pt-4 flex flex-wrap gap-2"><?php $d=['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];foreach($hours as$h):?><span class="bg-slate-100 rounded-lg px-2 py-1 text-xs"><?=$d[$h['dia_semana']]?> <?=substr($h['hora_inicio'],0,5)?>–<?=substr($h['hora_fin'],0,5)?> · <?=htmlspecialchars($h['profesional']?:$h['sucursal']?:'General')?></span><?php endforeach;if(!$hours):?><span class="text-xs text-amber-700">Sin horarios configurados: el motor no puede reservar.</span><?php endif?></div></div><form class="border rounded-2xl p-5 space-y-3" onsubmit="settings(event)"><h2 class="font-semibold">Reglas</h2><label class="text-xs text-slate-500 block">Anticipación mínima<input name="min_notice_hours" type="number" min="0" value="<?= (int)$settings['min_notice_hours']?>" class="border rounded p-2 mt-1 w-full"></label><label class="text-xs text-slate-500 block">Anticipación máxima<input name="max_advance_days" type="number" min="1" value="<?= (int)$settings['max_advance_days']?>" class="border rounded p-2 mt-1 w-full"></label><label class="text-xs text-slate-500 block">Espacio entre citas<input name="buffer_minutes" type="number" min="0" value="<?= (int)$settings['buffer_minutes']?>" class="border rounded p-2 mt-1 w-full"></label><button class="bg-slate-900 text-white rounded-lg w-full p-2 text-sm">Guardar</button></form></section></div>
<div id="modal" class="hidden fixed inset-0 bg-slate-950/40 z-50 p-4 overflow-auto"><div class="bg-white max-w-lg mx-auto mt-10 rounded-2xl p-6"><div class="flex justify-between"><h2 id="mt" class="font-bold text-lg"></h2><button onclick="modal.classList.add('hidden')">✕</button></div><div id="mb" class="mt-4"></div></div></div>
<script>
const services=<?=json_encode($services)?>,pros=<?=json_encode($professionals)?>,branches=<?=json_encode($branches)?>;const f=x=>Object.fromEntries(new FormData(x));async function api(x){let r=await fetch('ajax/agenda.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(x)}),j=await r.json();if(!j.success)throw Error(j.error);return j}function open(t,h){mt.textContent=t;mb.innerHTML=h;modal.classList.remove('hidden')}function entity(x){let extra=x==='servicios'?'<label>Duración (min)<input type="number" name="duracion_minutos" value="30" class="border rounded p-2 w-full"></label><label class="text-sm"><input type="checkbox" name="requiere_aprobacion"> Requiere aprobación</label>':x==='profesionales'?'<label>Especialidad<input name="especialidad" class="border rounded p-2 w-full"></label><label>Sucursal<select name="sucursal_id" class="border rounded p-2 w-full"><option value="">Sin preferencia</option>'+branches.map(b=>'<option value="'+b.id+'">'+b.nombre+'</option>').join('')+'</select></label>':'<label>Dirección<input name="direccion" class="border rounded p-2 w-full"></label>';open('Agregar '+x,'<form class="space-y-3" onsubmit="saveEntity(event,\''+x+'\')"><label>Nombre<input required name="nombre" class="border rounded p-2 w-full"></label>'+extra+'<label class="text-sm"><input checked type="checkbox" name="activo"> Activo</label><button class="bg-emerald-600 text-white px-4 py-2 rounded">Guardar</button></form>')}async function saveEntity(e,x){e.preventDefault();try{await api({...f(e.target),action:'save_entity',entity:x});location.reload()}catch(e){alert(e.message)}}function openHours(){open('Agregar horario','<form class="space-y-3" onsubmit="saveHours(event)"><label>Profesional<select name="profesional_id" class="border rounded p-2 w-full"><option value="">General</option>'+pros.map(p=>'<option value="'+p.id+'">'+p.nombre+'</option>').join('')+'</select></label><label>Sucursal<select name="sucursal_id" class="border rounded p-2 w-full"><option value="">Sin sucursal</option>'+branches.map(b=>'<option value="'+b.id+'">'+b.nombre+'</option>').join('')+'</select></label><label>Día<select name="dia_semana" class="border rounded p-2 w-full">'+['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'].map((x,i)=>'<option value="'+i+'">'+x+'</option>').join('')+'</select></label><div class="grid grid-cols-2 gap-3"><input required type="time" name="hora_inicio" class="border rounded p-2"><input required type="time" name="hora_fin" class="border rounded p-2"></div><button class="bg-emerald-600 text-white px-4 py-2 rounded">Guardar</button></form>')}async function saveHours(e){e.preventDefault();try{await api({...f(e.target),action:'save_hours'});location.reload()}catch(e){alert(e.message)}}function openBooking(){open('Nueva cita','<form class="space-y-3" onsubmit="book(event)"><label>Cliente<input required name="nombre_cliente" class="border rounded p-2 w-full"></label><label>Teléfono<input name="telefono" class="border rounded p-2 w-full"></label><label>Servicio<select required name="servicio_id" class="border rounded p-2 w-full">'+services.filter(s=>s.activo).map(s=>'<option value="'+s.id+'">'+s.nombre+'</option>').join('')+'</select></label><label>Profesional<select name="profesional_id" class="border rounded p-2 w-full"><option value="">Cualquiera</option>'+pros.filter(p=>p.activo).map(p=>'<option value="'+p.id+'">'+p.nombre+'</option>').join('')+'</select></label><label>Fecha y hora<input required type="datetime-local" name="inicio" class="border rounded p-2 w-full"></label><label>Motivo<textarea name="motivo" class="border rounded p-2 w-full"></textarea></label><button class="bg-emerald-600 text-white px-4 py-2 rounded">Crear cita</button></form>')}async function book(e){e.preventDefault();try{await api({...f(e.target),action:'create',canal:'manual'});location.reload()}catch(e){alert(e.message)}}async function status(id,s){try{await api({action:'status',id,status:s})}catch(e){alert(e.message);location.reload()}}async function settings(e){e.preventDefault();try{await api({...f(e.target),action:'save_settings'});alert('Reglas guardadas')}catch(e){alert(e.message)}}
</script>
<?php $mainContent=ob_get_clean();require __DIR__.'/includes/layout_tailwind.php';
